from __future__ import annotations

from dataclasses import dataclass
from random import Random
from typing import Final
from collections import deque

WALL: Final[str] = "#"
FLOOR: Final[str] = "."
PLAYER: Final[str] = "@"

@dataclass(frozen=True)
class Point:
    x: int
    y: int

@dataclass
class Fighter:
    hp: int
    power: int

    @property
    def alive(self) -> bool:
        return self.hp > 0

@dataclass
class Entity:
    name: str
    pos: Point
    fighter: Fighter | None = None

@dataclass
class GameMap:
    width: int
    height: int
    tiles: list[list[str]]

    @classmethod
    def filled(cls, width: int, height: int, tile: str) -> GameMap:
        return cls(width, height, [[tile for _ in range(width)] for _ in range(height)])

    def in_bounds(self, point: Point) -> bool:
        return 0 <= point.x < self.width and 0 <= point.y < self.height

    def is_walkable(self, point: Point) -> bool:
        return self.in_bounds(point) and self.tiles[point.y][point.x] == FLOOR

    def count_floor_neighbors(self, point: Point) -> int:
        count = 0
        for dy in (-1, 0, 1):
            for dx in (-1, 0, 1):
                if dx == 0 and dy == 0:
                    continue
                neighbor = Point(point.x + dx, point.y + dy)
                if self.in_bounds(neighbor) and self.tiles[neighbor.y][neighbor.x] == FLOOR:
                    count += 1
        return count

def generate_cellular_automata(width: int, height: int, seed: int, fill_prob: float = 0.45) -> GameMap:
    rng = Random(seed)
    game_map = GameMap.filled(width, height, WALL)

    for y in range(height):
        for x in range(width):
            if rng.random() < fill_prob:
                game_map.tiles[y][x] = FLOOR

    for _ in range(4):
        new_tiles = [[WALL for _ in range(width)] for _ in range(height)]
        for y in range(height):
            for x in range(width):
                point = Point(x, y)
                floor_neighbors = game_map.count_floor_neighbors(point)
                if game_map.tiles[y][x] == FLOOR:
                    if floor_neighbors >= 4:
                        new_tiles[y][x] = FLOOR
                else:
                    if floor_neighbors >= 5:
                        new_tiles[y][x] = FLOOR
        game_map.tiles = new_tiles

    return game_map

