from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True, slots=True)
class Point:
    x: int
    y: int


def in_bounds(grid: list[list[bool]], point: Point) -> bool:
    return 0 <= point.y < len(grid) and 0 <= point.x < len(grid[point.y])


def blocks_sight(grid: list[list[bool]], point: Point) -> bool:
    if not in_bounds(grid, point):
        return True
    return grid[point.y][point.x]


def bresenham_line(start: Point, end: Point) -> list[Point]:
    points: list[Point] = []
    x = start.x
    y = start.y
    dx = abs(end.x - start.x)
    dy = -abs(end.y - start.y)
    step_x = 1 if start.x < end.x else -1
    step_y = 1 if start.y < end.y else -1
    error = dx + dy
    while True:
        points.append(Point(x, y))
        if x == end.x and y == end.y:
            return points
        twice_error = 2 * error
        if twice_error >= dy:
            error += dy
            x += step_x
        if twice_error <= dx:
            error += dx
            y += step_y


def perimeter_points(origin: Point, radius: int) -> list[Point]:
    if radius < 0:
        raise ValueError("radius must be non-negative")
    if radius == 0:
        return [origin]
    points: list[Point] = []
    left = origin.x - radius
    right = origin.x + radius
    top = origin.y - radius
    bottom = origin.y + radius
    for x in range(left, right + 1):
        points.append(Point(x, top))
        points.append(Point(x, bottom))
    for y in range(top + 1, bottom):
        points.append(Point(left, y))
        points.append(Point(right, y))
    return points


def compute_fov(grid: list[list[bool]], origin: Point, radius: int) -> set[Point]:
    if not in_bounds(grid, origin):
        raise ValueError("origin must be inside the map")
    visible: set[Point] = {origin}
    for target in perimeter_points(origin, radius):
        for point in bresenham_line(origin, target)[1:]:
            distance = max(abs(point.x - origin.x), abs(point.y - origin.y))
            if distance > radius:
                break
            if not in_bounds(grid, point):
                break
            visible.add(point)
            if blocks_sight(grid, point):
                break
    return visible


def test_radius_zero_only_origin() -> None:
    grid = [[False, False], [False, False]]
    assert compute_fov(grid, Point(0, 0), 0) == {Point(0, 0)}


def test_wall_visible_but_tile_behind_hidden() -> None:
    grid = [[False, False, False, False, False]]
    grid[0][2] = True
    visible = compute_fov(grid, Point(0, 0), 4)
    assert Point(2, 0) in visible
    assert Point(3, 0) not in visible


def test_edges_do_not_escape_map() -> None:
    grid = [[False for _ in range(3)] for _ in range(3)]
    visible = compute_fov(grid, Point(0, 0), 5)
    assert visible == {Point(x, y) for y in range(3) for x in range(3)}
