from __future__ import annotations

from dataclasses import dataclass
from heapq import heappop, heappush


@dataclass(frozen=True, order=True, slots=True)
class Point:
    x: int
    y: int


def in_bounds(point: Point, width: int, height: int) -> bool:
    return 0 <= point.x < width and 0 <= point.y < height


def can_step_diagonal(current: Point, neighbor: Point, blocked: set[Point]) -> bool:
    dx = neighbor.x - current.x
    dy = neighbor.y - current.y
    if abs(dx) != 1 or abs(dy) != 1:
        return True
    return Point(current.x + dx, current.y) not in blocked and Point(current.x, current.y + dy) not in blocked


def neighbors(
    current: Point,
    blocked: set[Point],
    width: int,
    height: int,
    allow_diagonal: bool,
) -> list[Point]:
    offsets = [(1, 0), (0, 1), (-1, 0), (0, -1)]
    if allow_diagonal:
        offsets.extend([(1, 1), (1, -1), (-1, 1), (-1, -1)])
    result: list[Point] = []
    for dx, dy in offsets:
        candidate = Point(current.x + dx, current.y + dy)
        if not in_bounds(candidate, width, height):
            continue
        if candidate in blocked:
            continue
        if not can_step_diagonal(current, candidate, blocked):
            continue
        result.append(candidate)
    return result


def heuristic(a: Point, b: Point) -> int:
    return abs(a.x - b.x) + abs(a.y - b.y)


def reconstruct(came_from: dict[Point, Point], current: Point, start: Point) -> list[Point]:
    path = [current]
    while current != start:
        current = came_from[current]
        path.append(current)
    path.reverse()
    return path[1:]


def find_path(
    start: Point,
    goal: Point,
    blocked: set[Point],
    width: int,
    height: int,
    allow_diagonal: bool,
) -> list[Point] | None:
    if not in_bounds(start, width, height) or not in_bounds(goal, width, height):
        return None
    if start in blocked or goal in blocked:
        return None
    frontier: list[tuple[int, int, Point]] = []
    heappush(frontier, (0, 0, start))
    came_from: dict[Point, Point] = {}
    cost_so_far: dict[Point, int] = {start: 0}
    sequence = 0
    while frontier:
        _, _, current = heappop(frontier)
        if current == goal:
            return reconstruct(came_from, current, start)
        for neighbor in neighbors(current, blocked, width, height, allow_diagonal):
            new_cost = cost_so_far[current] + 1
            if neighbor in cost_so_far and new_cost >= cost_so_far[neighbor]:
                continue
            cost_so_far[neighbor] = new_cost
            came_from[neighbor] = current
            sequence += 1
            heappush(frontier, (new_cost + heuristic(neighbor, goal), sequence, neighbor))
    return None


def test_diagonal_cannot_cut_between_two_walls() -> None:
    blocked = {Point(1, 0), Point(0, 1)}
    assert find_path(Point(0, 0), Point(1, 1), blocked, 3, 3, True) is None


def test_diagonal_allowed_when_one_side_is_open() -> None:
    blocked = {Point(1, 0)}
    path = find_path(Point(0, 0), Point(1, 1), blocked, 3, 3, True)
    assert path == [Point(0, 1), Point(1, 1)]
