from __future__ import annotations

from dataclasses import dataclass, field


@dataclass(frozen=True, slots=True)
class Item:
    name: str
    stack_limit: int
    slot: str | None = None


@dataclass(slots=True)
class Inventory:
    counts: dict[Item, int] = field(default_factory=dict)
    equipped: dict[str, Item] = field(default_factory=dict)


def add_item(inventory: Inventory, item: Item, amount: int) -> bool:
    if amount <= 0:
        return False
    current = inventory.counts.get(item, 0)
    if current + amount > item.stack_limit:
        return False
    inventory.counts[item] = current + amount
    return True


def remove_item(inventory: Inventory, item: Item, amount: int) -> bool:
    current = inventory.counts.get(item, 0)
    if amount <= 0 or current < amount:
        return False
    remaining = current - amount
    if remaining == 0:
        del inventory.counts[item]
    else:
        inventory.counts[item] = remaining
    return True


def equip(inventory: Inventory, item: Item) -> bool:
    if item.slot is None or inventory.counts.get(item, 0) <= 0:
        return False
    if item.slot in inventory.equipped:
        return False
    inventory.equipped[item.slot] = item
    return True


def unequip(inventory: Inventory, slot: str) -> bool:
    if slot not in inventory.equipped:
        return False
    del inventory.equipped[slot]
    return True


def test_add_rejects_stack_overflow_without_changing_count() -> None:
    potion = Item("healing potion", 3)
    inventory = Inventory()
    assert add_item(inventory, potion, 2)
    assert not add_item(inventory, potion, 2)
    assert inventory.counts[potion] == 2


def test_failed_remove_preserves_stack() -> None:
    scroll = Item("blink scroll", 5)
    inventory = Inventory(counts={scroll: 1})
    assert not remove_item(inventory, scroll, 2)
    assert inventory.counts[scroll] == 1


def test_equipment_slot_is_exclusive_until_unequipped() -> None:
    dagger = Item("dagger", 1, "hand")
    mace = Item("mace", 1, "hand")
    inventory = Inventory(counts={dagger: 1, mace: 1})
    assert equip(inventory, dagger)
    assert not equip(inventory, mace)
    assert inventory.equipped["hand"] == dagger
    assert unequip(inventory, "hand")
    assert equip(inventory, mace)
